import{_ as e,o as a,c as t,af as r}from"./chunks/framework.5D6DWnkB.js";const k=JSON.parse('{"title":"给静态博客加上灵魂：PVE 旁路部署 Twikoo 评论系统实战","description":"","frontmatter":{"title":"给静态博客加上灵魂：PVE 旁路部署 Twikoo 评论系统实战","date":"2026-04-05T00:00:00.000Z","category":"建站"},"headers":[],"relativePath":"tools/twikoo-rss.md","filePath":"tools/twikoo-rss.md"}'),s={name:"tools/twikoo-rss.md"};function i(d,o,c,n,l,p){return a(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="给静态博客加上灵魂-pve-旁路部署-twikoo-评论系统实战" tabindex="-1">给静态博客加上灵魂：PVE 旁路部署 Twikoo 评论系统实战 <a class="header-anchor" href="#给静态博客加上灵魂-pve-旁路部署-twikoo-评论系统实战" aria-label="Permalink to &quot;给静态博客加上灵魂：PVE 旁路部署 Twikoo 评论系统实战&quot;">​</a></h1><p>当你搭好了一个极简的 VitePress 博客，有了独立域名，也写了几篇文章后，你会发现它少了点“人情味”——读者看完了，想吐槽一句，却发现连个评论框都没有。</p><p>纯静态博客天然不支持动态交互，但借助像 Twikoo 这样的无后端评论系统，我们完全可以把这块“动态拼图”补上。</p><h2 id="架构解耦-为什么不在博客宿主机混装" tabindex="-1">架构解耦：为什么不在博客宿主机混装？ <a class="header-anchor" href="#架构解耦-为什么不在博客宿主机混装" aria-label="Permalink to &quot;架构解耦：为什么不在博客宿主机混装？&quot;">​</a></h2><p>最初我想图省事，直接在跑着博客源码的虚拟机里（103）用 Docker 跑一个 Twikoo 后端。但后来采纳了老冯的建议：<strong>架构必须解耦</strong>。</p><p>博客宿主机只管前端源码和编译；任何对外的、涉及到数据库读写的后端服务，都应该切分出来。</p><p>于是，我直接在 PVE 宿主机上，一键秒开了一个<strong>专属的 LXC 容器（编号 104，Debian 12系统）</strong>，专门用来跑 Twikoo 后端。哪怕以后评论系统被 D 死了，也绝对不会影响博客主站的稳定。</p><h2 id="踩坑录-那些环境与网络的折磨" tabindex="-1">踩坑录：那些环境与网络的折磨 <a class="header-anchor" href="#踩坑录-那些环境与网络的折磨" aria-label="Permalink to &quot;踩坑录：那些环境与网络的折磨&quot;">​</a></h2><p>在 LXC 里跑 Docker 安装 Twikoo 时，遇到了经典的双重网络打击。</p><h3 id="_1-dns-罢工" tabindex="-1">1. DNS 罢工 <a class="header-anchor" href="#_1-dns-罢工" aria-label="Permalink to &quot;1. DNS 罢工&quot;">​</a></h3><p>LXC 刚建好，执行 <code>apt update</code> 就全部报错解析失败。排查发现是底层配置没把 DNS 传进来。 <strong>解法</strong>：直接暴力修改底层的 <code>/etc/resolv.conf</code>，强行注入了公共 DNS（如 <code>223.5.5.5</code>），网络瞬间打通。</p><h3 id="_2-docker-镜像墙" tabindex="-1">2. Docker 镜像墙 <a class="header-anchor" href="#_2-docker-镜像墙" aria-label="Permalink to &quot;2. Docker 镜像墙&quot;">​</a></h3><p>国内直连 Docker Hub 的墙越来越高，拉取 Twikoo 的官方镜像一直卡在 <code>waiting</code> 直到超时。 <strong>解法</strong>：去配了国内的 Docker 镜像加速源（如各大云厂商的镜像库或者代理库），重启 Docker 后，秒级拉取成功并启动。</p><h2 id="前端改造与-rss-订阅附赠" tabindex="-1">前端改造与 RSS 订阅附赠 <a class="header-anchor" href="#前端改造与-rss-订阅附赠" aria-label="Permalink to &quot;前端改造与 RSS 订阅附赠&quot;">​</a></h2><p>Twikoo 后端（<code>192.168.1.104:8080</code>）跑起来后，剩下的就是前端的活儿了。</p><p>在 103 虚拟机的 <code>vitepress-demo</code> 源码中：</p><ol><li><strong>注入组件</strong>：我在全局的主题配置里，把 Twikoo 的前端组件给挂载进去了。现在每篇文章底下，都会自动浮现出清爽的评论框。</li><li><strong>顺手加上了 RSS</strong>：既然动了配置，干脆一步到位。引入了 <code>feed</code> 模块，配置了一下 <code>config.js</code>。现在每次触发 <code>docs:build</code> 时，系统不仅会渲染网页，还会自动生成一个 <code>feed.xml</code> 放在根目录。那些喜欢用 RSS 阅读器的大佬，终于可以订阅我的博客了。</li></ol><p>最后，执行了一把 <code>git commit</code> 和 <code>push</code>。眼看着 Cloudflare Pages 的流水线跑完，绿灯亮起。去线上刷一下，评论框和 RSS 订阅完美上线！</p><hr><p>至此，这个博客才算是一座真正的“数字驿站”。欢迎大家留言踩一踩。</p>',20)])])}const _=e(s,[["render",i]]);export{k as __pageData,_ as default};
